solution:
def max_profit(a):
    if not a:
        return 0
    best = 0
    lo = a[0]
    for i in range(1, len(a)):
        if a[i] - lo > best:
            best = a[i] - lo
        if a[i] < lo:
            lo = a[i]
    return best
